const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { v4: uuidv4 } = require('uuid');

// 安全头配置
const securityHeaders = helmet({
  // 内容安全策略
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      styleSrc: ["'self'", "'unsafe-inline'", "https://fonts.googleapis.com"],
      fontSrc: ["'self'", "https://fonts.gstatic.com"],
      imgSrc: ["'self'", "data:", "https:", "blob:"],
      scriptSrc: ["'self'", "'unsafe-inline'", "'unsafe-eval'"],
      connectSrc: ["'self'", "ws:", "wss:", "https:"],
      frameSrc: ["'none'"],
      objectSrc: ["'none'"],
      upgradeInsecureRequests: []
    }
  },
  // 严格传输安全
  hsts: {
    maxAge: 31536000,
    includeSubDomains: true,
    preload: true
  },
  // 防止点击劫持
  frameguard: {
    action: 'deny'
  },
  // 防止MIME类型嗅探
  noSniff: true,
  // 防止XSS攻击
  xssFilter: true,
  // 隐藏服务器信息
  hidePoweredBy: true,
  // 防止IE打开下载的文件
  ieNoOpen: true,
  // 防止DNS预取
  dnsPrefetchControl: {
    allow: false
  }
});

// CSRF保护中间件
const csrfProtection = (req, res, next) => {
  // 跳过GET请求和健康检查
  if (req.method === 'GET' || req.path === '/api/health') {
    return next();
  }

  // 对于像素战争游戏，我们采用简化的CSRF保护
  // 检查请求来源和Referer头
  const origin = req.headers.origin;
  const referer = req.headers.referer;
  const allowedOrigins = [
    process.env.CORS_ORIGIN || "http://localhost:5173",
    "http://localhost:3000",
    "http://localhost:5173",
    "http://127.0.0.1:5173",
    "http://127.0.0.1:3000"
  ];

  // 检查Origin头
  if (origin && !allowedOrigins.includes(origin)) {
    console.warn(`🚨 可疑的Origin: ${origin} from ${req.ip}`);
    return res.status(403).json({
      success: false,
      error: 'CSRF_TOKEN_INVALID',
      message: '请求来源不被允许'
    });
  }

  // 检查Referer头（如果存在）
  if (referer) {
    const refererUrl = new URL(referer);
    const isAllowedReferer = allowedOrigins.some(allowedOrigin => {
      const allowedUrl = new URL(allowedOrigin);
      return refererUrl.origin === allowedUrl.origin;
    });

    if (!isAllowedReferer) {
      console.warn(`🚨 可疑的Referer: ${referer} from ${req.ip}`);
      return res.status(403).json({
        success: false,
        error: 'CSRF_TOKEN_INVALID',
        message: '请求来源不被允许'
      });
    }
  }

  next();
};

// 生成CSRF令牌
const generateCSRFToken = () => {
  return uuidv4();
};

// 输入验证和清理中间件
const inputValidation = (req, res, next) => {
  // 清理请求体
  if (req.body) {
    req.body = sanitizeInput(req.body);
  }

  // 清理查询参数
  if (req.query) {
    req.query = sanitizeInput(req.query);
  }

  // 清理URL参数
  if (req.params) {
    req.params = sanitizeInput(req.params);
  }

  next();
};

// 输入清理函数
const sanitizeInput = (obj) => {
  if (typeof obj !== 'object' || obj === null) {
    return sanitizeString(obj);
  }

  const cleaned = Array.isArray(obj) ? [] : {};
  
  for (const [key, value] of Object.entries(obj)) {
    if (typeof value === 'object' && value !== null) {
      cleaned[key] = sanitizeInput(value);
    } else {
      cleaned[key] = sanitizeString(value);
    }
  }

  return cleaned;
};

// 字符串清理函数
const sanitizeString = (str) => {
  if (typeof str !== 'string') {
    return str;
  }

  return str
    .replace(/[<>]/g, '') // 移除尖括号
    .replace(/javascript:/gi, '') // 移除javascript协议
    .replace(/on\w+=/gi, '') // 移除事件处理器
    .trim();
};

// 错误处理中间件
const errorHandler = (err, req, res, next) => {
  // 记录错误日志
  console.error('错误详情:', {
    timestamp: new Date().toISOString(),
    method: req.method,
    url: req.url,
    ip: req.ip,
    userAgent: req.get('User-Agent'),
    error: err.message,
    stack: process.env.NODE_ENV === 'development' ? err.stack : undefined
  });

  // 不暴露敏感信息
  const errorResponse = {
    success: false,
    error: 'INTERNAL_SERVER_ERROR',
    message: process.env.NODE_ENV === 'production' 
      ? '服务器内部错误' 
      : err.message
  };

  // 根据错误类型返回不同的状态码
  if (err.name === 'ValidationError') {
    return res.status(400).json({
      ...errorResponse,
      error: 'VALIDATION_ERROR',
      message: '输入验证失败'
    });
  }

  if (err.name === 'UnauthorizedError') {
    return res.status(401).json({
      ...errorResponse,
      error: 'UNAUTHORIZED',
      message: '未授权访问'
    });
  }

  res.status(500).json(errorResponse);
};

// 请求日志中间件
const requestLogger = (req, res, next) => {
  const startTime = Date.now();
  
  // 记录请求开始
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.url} - ${req.ip}`);
  
  // 记录响应完成
  res.on('finish', () => {
    const duration = Date.now() - startTime;
    console.log(`[${new Date().toISOString()}] ${req.method} ${req.url} - ${res.statusCode} - ${duration}ms`);
  });

  next();
};

// 安全日志中间件
const securityLogger = (req, res, next) => {
  // 检测可疑请求
  const suspiciousPatterns = [
    /<script/i,
    /javascript:/i,
    /on\w+=/i,
    /union\s+select/i,
    /drop\s+table/i,
    /delete\s+from/i
  ];

  const requestString = JSON.stringify({
    url: req.url,
    body: req.body,
    query: req.query,
    headers: req.headers
  });

  for (const pattern of suspiciousPatterns) {
    if (pattern.test(requestString)) {
      console.warn(`🚨 检测到可疑请求: ${req.ip} - ${req.method} ${req.url}`);
      // 这里可以添加告警通知
      break;
    }
  }

  next();
};

// 会话安全中间件
const sessionSecurity = (req, res, next) => {
  // 设置安全的cookie选项
  const sessionId = req.sessionID || uuidv4();
  res.cookie('sessionId', sessionId, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: 24 * 60 * 60 * 1000 // 24小时
  });

  // 初始化session对象（如果不存在）
  if (!req.session) {
    req.session = {};
  }

  // 生成CSRF令牌
  if (!req.session.csrfToken) {
    req.session.csrfToken = generateCSRFToken();
  }

  next();
};

// 文件上传安全检查
const fileUploadSecurity = (req, res, next) => {
  if (!req.file && !req.files) {
    return next();
  }

  const allowedMimeTypes = [
    'image/jpeg',
    'image/png',
    'image/gif',
    'image/webp'
  ];

  const maxFileSize = 5 * 1024 * 1024; // 5MB

  const files = req.file ? [req.file] : req.files;

  for (const file of files) {
    // 检查文件类型
    if (!allowedMimeTypes.includes(file.mimetype)) {
      return res.status(400).json({
        success: false,
        error: 'INVALID_FILE_TYPE',
        message: '不支持的文件类型'
      });
    }

    // 检查文件大小
    if (file.size > maxFileSize) {
      return res.status(400).json({
        success: false,
        error: 'FILE_TOO_LARGE',
        message: '文件大小超过限制'
      });
    }

    // 检查文件扩展名
    const allowedExtensions = ['.jpg', '.jpeg', '.png', '.gif', '.webp'];
    const fileExtension = file.originalname.toLowerCase().substring(
      file.originalname.lastIndexOf('.')
    );

    if (!allowedExtensions.includes(fileExtension)) {
      return res.status(400).json({
        success: false,
        error: 'INVALID_FILE_EXTENSION',
        message: '不支持的文件扩展名'
      });
    }
  }

  next();
};

module.exports = {
  securityHeaders,
  csrfProtection,
  generateCSRFToken,
  inputValidation,
  errorHandler,
  requestLogger,
  securityLogger,
  sessionSecurity,
  fileUploadSecurity
};
